#include<bits/stdc++.h>
using namespace std;
int main(void){
	int f[2]={11,21},a[25*2500+10],sum=0,w,l;char c;
    while(cin>>c&&c!='E'){
        if(c=='W')a[sum++]=1;
        else if(c=='L')a[sum++]=0;
    }
    for(int i=0;i<2;i++){
    	w=l=0;
        for(int j=0;j<sum;j++){
            w+=a[j],l-=a[j]-1;
            if((max(w,l)>=f[i])&&abs(w-l)>=2){ 
                cout<<w<<':'<<l<<endl;w=l=0;
            }
        }
        cout<<w<<':'<<l<<endl<<endl;
    }
    return false;
}
